export async function seedSampleData(db: SQLite.SQLiteDatabase): Promise<void> {
  // Always check and update vocabulary
  const existingWords = await db.getFirstAsync<{ count: number }>(
    'SELECT COUNT(*) as count FROM words WHERE book_id = ?',
    ['hongbaoshu_kaoyan']
  );

  // If word count doesn't match our expected count, re-import
  if (!existingWords || existingWords.count !== KAOYAN_WORDS.length) {
    console.log('Updating vocabulary data...');

    // Clear existing data for this book
    await db.runAsync('DELETE FROM cards WHERE word_id IN (SELECT id FROM words WHERE book_id = ?)', ['hongbaoshu_kaoyan']);
    await db.runAsync('DELETE FROM words WHERE book_id = ?', ['hongbaoshu_kaoyan']);
    await db.runAsync('DELETE FROM books WHERE id = ?', ['hongbaoshu_kaoyan']);

    await importBookAndWords(
      db,
      'hongbaoshu_kaoyan',
      '红宝书考研英语词汇（乱序版）',
      KAOYAN_WORDS
    );
    console.log(`Updated to ${KAOYAN_WORDS.length} words`);
  } else {
    console.log(`Vocabulary already loaded: ${existingWords.count} words`);
  }
}
